import{c as s,S as i,j as a,m as t}from"./chunks/framework.DvQr6YbT.js";const g=JSON.parse('{"title":"Working with Multiple Knowledge Bases","description":"","frontmatter":{},"headers":[],"relativePath":"guides/multiple-knowledge-bases.md","filePath":"guides/multiple-knowledge-bases.md","lastUpdated":1783440616000}'),n={name:"guides/multiple-knowledge-bases.md"};function l(r,e,o,h,d,k){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="working-with-multiple-knowledge-bases" tabindex="-1">Working with Multiple Knowledge Bases <a class="header-anchor" href="#working-with-multiple-knowledge-bases" aria-label="Permalink to “Working with Multiple Knowledge Bases”">​</a></h1><p>One vault for work, one for personal research, one for a side project — as soon as there is more than one, &quot;which folder am I in?&quot; becomes friction. The <strong>KB registry</strong> gives knowledge bases names.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/vaults/work-kb</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> personal</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/vaults/personal</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --kb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;what did we decide about the rollout?&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stale</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --kb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> personal</span></span></code></pre></div><p><code>--kb &lt;name&gt;</code> works on every command that operates on an existing KB, from any directory. <code>--dir</code> keeps working exactly as before — <code>--kb</code> is a convenience on top, and the registry is never required (<code>init</code> doesn&#39;t take <code>--kb</code>: initialize first, then register).</p><h2 id="the-registry" tabindex="-1">The registry <a class="header-anchor" href="#the-registry" aria-label="Permalink to “The registry”">​</a></h2><p>A plain address book at <code>~/.config/knowlery/registry.json</code> — names and paths, nothing else.</p><ul><li><code>knowlery kb list</code> shows each KB&#39;s live state: <code>ok</code>, <code>uninitialized</code> (folder exists, not a workspace), or <code>missing</code> (moved/deleted — entries are flagged, never auto-removed).</li><li><code>knowlery kb remove &lt;name&gt;</code> removes the registry entry only; the knowledge base&#39;s files are untouched.</li><li>If the registry file is ever corrupted, Knowlery reports it loudly and does <strong>not</strong> reset it — it&#39;s your list of your knowledge bases.</li></ul><h2 id="searching-everything-at-once" tabindex="-1">Searching everything at once <a class="header-anchor" href="#searching-everything-at-once" aria-label="Permalink to “Searching everything at once”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --kb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;*&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;where did I write about backpressure?&quot;</span></span></code></pre></div><p>Runs the retrieval engine over every registered KB and merges the results by score, each line naming its KB:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>  31.42  work: concepts/backpressure.md — Backpressure</span></span>
<span class="line"><span>   8.91  personal: concepts/flow-control.md — Flow Control</span></span></code></pre></div><p>Unreachable or uninitialized KBs are skipped with a note; if nothing answers confidently anywhere, the abstention message lists which KBs were consulted.</p><h2 id="vaults-in-obsidian-register-themselves" tabindex="-1">Vaults in Obsidian register themselves <a class="header-anchor" href="#vaults-in-obsidian-register-themselves" aria-label="Permalink to “Vaults in Obsidian register themselves”">​</a></h2><p>A vault set up with the Knowlery plugin registers itself under its knowledge base name (a numeric suffix is added if the name is taken). The settings toggle <strong>&quot;Register vault for CLI/agent access&quot;</strong> controls this; turning it off removes only the entry the plugin itself created — a name you registered manually is never touched.</p>`,14)])])}const c=s(n,[["render",l]]);export{g as __pageData,c as default};
